const buttonStyles = css`
  background-color: #4CAF50;
  color: #fff;
  padding: 10px 20px;
  border: none;
  border-radius: 5px;
  cursor: pointer;
`;

const MyButton = () => {
  return (
    <button style={buttonStyles}>{'Click me!'}</button>
